/**
 * deferred-reconcile.mjs — reconcile Clippings/_deferred.md tail-skipped rows
 * when a github subject is promoted (LUNA-89).
 *
 * `_deferred.md` (generated by /archive-clips Phase 5) lists, under
 * "## Tail-skipped refs (luna-ingest --limit cap)", rows like:
 *
 *   - [ ] acme/agent-kit — 178 refs beyond --limit; re-run `/luna-ingest <url> --limit 200`
 *
 * When a github evidence clip for `acme/agent-kit` is promoted to a Tech
 * subject, that backlog row now has an owning home — so we CLAIM it: flip the
 * checkbox and append a `promoted → [[subject]]` note, keeping the original
 * ref-count + re-run hint intact (the actual one-hop crawl is /deepen-subject).
 *
 * Pure string surgery, no I/O. Literal, reversible: the caller records oldLine
 * + newLine so a revert restores the row verbatim.
 */

/** "owner/repo" for a canonical github URL, else null. Lowercased (canonical already is). */
export function repoSlugFromCanonical(canonicalUrl) {
  if (!canonicalUrl) return null;
  let u;
  try { u = new URL(canonicalUrl); } catch { return null; }
  if (u.hostname.toLowerCase() !== "github.com") return null;
  const parts = u.pathname.split("/").filter(Boolean);
  if (parts.length < 2) return null;
  return `${parts[0]}/${parts[1]}`.toLowerCase();
}

function stripCR(s) { return s.endsWith("\r") ? s.slice(0, -1) : s; }

/**
 * Claim the open tail-skipped row for `repoSlug`. Matches a line that, after
 * trimming a trailing '\r', starts with `- [ ] <repoSlug> ` (slug followed by a
 * space, so `acme/agent-kit` does not match `acme/agent-kit-extra`).
 *
 * @returns {{newContent, oldLine, newLine}|null} null when no open row matches.
 */
export function claimTailSkippedRow(content, repoSlug, subjectLink, date) {
  const lines = content.split("\n");
  // Case-insensitive: repoSlug is lowercased by repoSlugFromCanonical, but the
  // row's slug is grepped from a Tech page's audit log whose casing is not
  // guaranteed. Compare lowercased so a mixed-case row still matches.
  const prefix = `- [ ] ${repoSlug.toLowerCase()} `;
  for (let i = 0; i < lines.length; i++) {
    const bare = stripCR(lines[i]);
    if (!bare.toLowerCase().startsWith(prefix)) continue;
    const cr = lines[i].endsWith("\r") ? "\r" : "";
    const oldLine = lines[i];
    // Flip checkbox + append the promotion note; keep the original tail intact.
    const newBare = bare.replace("- [ ] ", "- [x] ") + ` — promoted → ${subjectLink} (${date})`;
    const newLine = newBare + cr;
    const newLines = lines.slice(0, i).concat([newLine], lines.slice(i + 1));
    return { newContent: newLines.join("\n"), oldLine, newLine };
  }
  return null;
}
